const { ChatOpenAI } = require('@langchain/openai');
const { HumanMessage, SystemMessage } = require('@langchain/core/messages');
const { DynamicTool } = require('@langchain/core/tools');
const { AgentExecutor, createOpenAIFunctionsAgent } = require('langchain/agents');
const { ChatPromptTemplate, MessagesPlaceholder } = require('@langchain/core/prompts');

const llm = new ChatOpenAI({
  apiKey: $env.OPENAI_API_KEY,
  modelName: 'gpt-4o-mini',
  temperature: 0.1,
});

// Herramientas que el agente puede decidir usar
const tools = [
  new DynamicTool({
    name: 'buscar_precio_producto',
    description: `Busca el precio de un producto por SKU.
      Input: SKU del producto (ej: SKU-001).
      Output: nombre y precio en pesos.`,
    func: async (sku) => {
      const precios = {
        'SKU-001': { nombre: 'Notebook Dell', precio: 850000 },
        'SKU-002': { nombre: 'Monitor LG 24"', precio: 320000 },
        'SKU-003': { nombre: 'Teclado Logitech', precio: 95000 }
      };
      const producto = precios[sku.trim().toUpperCase()];
      return producto
        ? `Producto: ${producto.nombre} | Precio: $${producto.precio.toLocaleString('es-AR')}`
        : `Producto con SKU ${sku} no encontrado`;
    }
  }),

  new DynamicTool({
    name: 'calcular_descuento',
    description: `Calcula el precio final con descuento.
      Input: JSON string con formato {"precio": NUMBER, "descuento_pct": NUMBER}.
      Output: precio final calculado.`,
    func: async (inputStr) => {
      try {
        const { precio, descuento_pct } = JSON.parse(inputStr);
        const precioFinal = precio - (precio * descuento_pct / 100);
        return `Precio original: $${precio} | Descuento: ${descuento_pct}% | Precio final: $${precioFinal}`;
      } catch {
        return 'Error: el input debe ser JSON con precio y descuento_pct';
      }
    }
  })
];

// createOpenAIFunctionsAgent es más estable que createReactAgent en n8n
// Requiere MessagesPlaceholder('agent_scratchpad') — es donde el agente
// escribe su razonamiento interno entre pasos
const prompt = ChatPromptTemplate.fromMessages([
  new SystemMessage(`Sos un asistente de ventas de TechStore.
Tenés herramientas para buscar precios y calcular descuentos.
Usá las herramientas cuando el cliente pregunte por productos o precios.`),
  new MessagesPlaceholder('chat_history'),
  ['human', '{input}'],
  new MessagesPlaceholder('agent_scratchpad')
]);

const agente = await createOpenAIFunctionsAgent({ llm, tools, prompt });

const executor = new AgentExecutor({
  agent: agente,
  tools: tools,
  maxIterations: 5,
  returnIntermediateSteps: true
});

const items = $input.all();

const resultados = await Promise.all(
  items.map(async (item) => {

    const resultado = await executor.invoke({
      input: item.json.chatInput,
      chat_history: []  // podés pasar historial previo acá si tenés memoria
    });

    return {
      json: {
        sessionId: item.json.sessionId,
        chatInput: item.json.chatInput,
        respuesta: resultado.output,
        // pasos muestra exactamente qué herramienta usó el agente y por qué
        pasos: resultado.intermediateSteps.map(s => ({
          tool_usada: s.action.tool,
          input_enviado: s.action.toolInput,
          resultado_recibido: s.observation
        })),
        procesado_en: new Date().toISOString()
      }
    };
  })
);

return resultados;
